import React, { useState, useEffect, useRef, useCallback } from "react";
import { useGoogleLogin, googleLogout } from '@react-oauth/google';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { ExpenseList, ExpenseForm, LoadingBar } from "./components/index";
import { MDCSnackbar } from "@material/snackbar/dist/mdc.snackbar.js";

import "@material/fab/dist/mdc.fab.css";
import "@material/button/dist/mdc.button.css";
import "@material/toolbar/dist/mdc.toolbar.css";
import "@material/snackbar/dist/mdc.snackbar.css";
import "@material/card/dist/mdc.card.css";

import "./App.css";

// --- COLORS FOR THE CHART ---
const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#AF19FF', '#FF1919', '#0019FF'];

const SPREADSHEET_ID = process.env.REACT_APP_SHEET_ID;

// Helper: Formats JS Date to "MM/DD/YYYY" for the UI to display
const formatDateForUI = (dateObj) => {
  const year = dateObj.getFullYear();
  const month = (dateObj.getMonth() + 1).toString().padStart(2, '0');
  const day = dateObj.getDate().toString().padStart(2, '0');
  return `${month}/${day}/${year}`;
};

const App = () => {
  // --- STATE MANAGEMENT ---
  const [activeView, setActiveView] = useState('other'); // 'other' or 'monthly'
  const [signedIn, setSignedIn] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [showExpenseForm, setShowExpenseForm] = useState(false);
  
  // Data State
  const [sheetIdMap, setSheetIdMap] = useState({});
  const [accounts, setAccounts] = useState([]);
  const [categories, setCategories] = useState([]);
  
  // "Other" expenses state
  const [expenses, setExpenses] = useState([]);
  const [currentMonth, setCurrentMonth] = useState(undefined);
  const [previousMonth, setPreviousMonth] = useState(undefined);
  const [categoryStats, setCategoryStats] = useState([]);

  // "Monthly" expenses state
  const [monthlyExpenses, setMonthlyExpenses] = useState([]);
  const [monthlyCurrentMonth, setMonthlyCurrentMonth] = useState(undefined);
  const [monthlyPreviousMonth, setMonthlyPreviousMonth] = useState(undefined);
  const [monthlyCategoryStats, setMonthlyCategoryStats] = useState([]);

  // Dashboard State
  const [filterCategory, setFilterCategory] = useState(null); 
  const [showChart, setShowChart] = useState(true);
  const [iconMap, setIconMap] = useState({});
  
  // Form State
  const [expense, setExpense] = useState({});

  // Refs
  const snackbarRef = useRef(null);
  const snackbarInstance = useRef(null);

  // --- GOOGLE AUTH ---
  const login = useGoogleLogin({
    onSuccess: async (tokenResponse) => {
      await loadGapiClient();
      window.gapi.client.setToken({ access_token: tokenResponse.access_token });
      setSignedIn(true);
      loadData();
    },
    onError: error => console.log('Login Failed:', error),
    scope: 'https://www.googleapis.com/auth/spreadsheets https://www.googleapis.com/auth/drive.metadata.readonly',
  });

  const logout = () => {
    googleLogout();
    setSignedIn(false);
    // Clear all data on logout
    setExpenses([]);
  };

  const loadGapiClient = () => {
    return new Promise((resolve) => {
      const script = document.createElement("script");
      script.src = "https://apis.google.com/js/api.js";
      script.onload = () => {
        window.gapi.load("client", () => {
          window.gapi.client.init({
            discoveryDocs: ["https://sheets.googleapis.com/$discovery/rest?version=v4"],
          }).then(resolve);
        });
      };
      document.body.appendChild(script);
    });
  };

  // --- ACTIONS ---
  const handleSliceClick = (data) => {
    if (filterCategory === data.name) {
      setFilterCategory(null);
    } else {
      setFilterCategory(data.name);
    }
  };

  const onExpenseNew = useCallback(() => {
    const now = new Date();
    // Format to YYYY-MM-DD for the form input
    const year = now.getFullYear();
    const month = (now.getMonth() + 1).toString().padStart(2, '0');
    const day = now.getDate().toString().padStart(2, '0');
    const dateForInput = `${year}-${month}-${day}`;
    setExpense({
      amount: "", description: "", date: dateForInput,
      category: categories[0] || "", account: accounts[0] || ""
    });
    setShowExpenseForm(true);
  }, [categories, accounts]);

  useEffect(() => {
    if (snackbarRef.current) snackbarInstance.current = new MDCSnackbar(snackbarRef.current);
    const handleKeyUp = (e) => {
      if (signedIn) {
        if (!showExpenseForm && e.keyCode === 65) onExpenseNew();
        else if (showExpenseForm && e.keyCode === 27) setShowExpenseForm(false);
      }
    };
    document.addEventListener("keyup", handleKeyUp);
    return () => document.removeEventListener("keyup", handleKeyUp);
  }, [signedIn, showExpenseForm, onExpenseNew]);

  // --- READ LOGIC (FROM SHEET TO APP) ---
  const parseExpense = (value, index, sheetName) => {
    // Robust Amount Cleaning
    let rawAmount = value[4] || "0";
    if (typeof rawAmount === 'string') {
        rawAmount = rawAmount.replace(/[^0-9.-]+/g, "");
    }
    const id = `${sheetName}!A${index + 2}`;

    // The sheet gives us "MM/DD/YYYY". We convert it to "YYYY-MM-DD"
    // for consistency within the app (e.g. for <input type="date">).
    let date = value[0] || "";
    if (date.includes('/')) {
      const parts = date.split('/');
      if (parts.length === 3) {
        date = `${parts[2]}-${parts[0].padStart(2, '0')}-${parts[1].padStart(2, '0')}`;
      }
    }

    return {
      id: id,
      date: date, 
      description: value[1],
      category: value[3] ? value[3].trim() : "Uncategorized",
      amount: rawAmount,
      account: value[2]
    };
  };

  // --- WRITE LOGIC (FROM APP TO SHEET) ---
  const formatExpense = (exp) => {
    // The UI gives us "MM/DD/YYYY" (e.g. "01/03/2026")
    // The UI provides dates in "YYYY-MM-DD" format from the <input type="date">
    const parts = exp.date.split('-'); 
    // parts[0] = Year, parts[1] = Month, parts[2] = Day

    // CRITICAL: We convert this string into the Google Sheets FORMULA
    // Input: "2026-01-03" -> Output: "=DATE(2026, 1, 3)"
    const dateFormula = `=DATE(${parts[0]}, ${parts[1]}, ${parts[2]})`;

    return [
      dateFormula,      // Column A: The Formula
      exp.description,  // Column B
      exp.account,      // Column C
      exp.category,     // Column D
      exp.amount        // Column E
    ];
  };

  // --- CHART STATS LOGIC ---
  const calculateStats = (allExpenses, forCurrentMonthOnly = true) => {
    const now = new Date();
    const currentMonth = now.getMonth(); 
    const currentYear = now.getFullYear();
    
    const statsMap = {};

    const expensesToProcess = forCurrentMonthOnly
      ? allExpenses.filter(exp => {
          const parts = exp.date.split('-');
          if (parts.length !== 3) return false;
          const expDate = new Date(parts[0], parts[1] - 1, parts[2]);
          return expDate.getMonth() === currentMonth && expDate.getFullYear() === currentYear;
        })
      : allExpenses;

    expensesToProcess.forEach(exp => {
      const amount = parseFloat(exp.amount) || 0;
      if (statsMap[exp.category]) {
        statsMap[exp.category] += amount;
      } else {
        statsMap[exp.category] = amount;
      }
    });

    const data = Object.keys(statsMap).map(cat => ({
      name: cat,
      value: statsMap[cat]
    }));
    
    return data.sort((a, b) => b.value - a.value);
  };

  const loadData = () => {
    setProcessing(true);

    // First, get sheet metadata to map names to IDs for the delete functionality
    window.gapi.client.sheets.spreadsheets.get({
        spreadsheetId: SPREADSHEET_ID
    }).then(metaResponse => {
        const newSheetIdMap = {};
        metaResponse.result.sheets.forEach(sheet => {
            newSheetIdMap[sheet.properties.title] = sheet.properties.sheetId;
        });
        setSheetIdMap(newSheetIdMap);

        // Now, fetch all the data
        window.gapi.client.sheets.spreadsheets.values.batchGet({
          spreadsheetId: SPREADSHEET_ID,
          valueRenderOption: 'FORMATTED_VALUE', 
          dateTimeRenderOption: 'FORMATTED_STRING',
          ranges: [
              "Data!A2:A50", "Data!E2:F50", // 0, 1
              "Expenses!A2:F", "Current!H1", "Previous!H1", // 2, 3, 4
              "Monthly!A2:F", "MonthlyCurrent!H1", "MonthlyPrevious!H1" // 5, 6, 7
          ]
        }).then(response => {
          const result = response.result.valueRanges;
          
          // Load Icons and Categories (shared)
          const categoryRows = result[1].values || [];
          const loadedCategories = categoryRows.map(row => row[0]);
          const loadedIconMap = categoryRows.reduce((acc, row) => {
              acc[row[0]] = row[1] || 'attach_money'; 
              return acc;
          }, {});

          // Load "Other" Expenses
          const loadedExpenses = (result[2].values || []).map((val, i) => parseExpense(val, i, 'Expenses')).reverse();
          
          // Load "Monthly" Expenses
          const loadedMonthlyExpenses = (result[5].values || []).map((val, i) => parseExpense(val, i, 'Monthly')).reverse();

          setAccounts(result[0].values ? result[0].values.map(i => i[0]) : []);
          setCategories(loadedCategories);
          setIconMap(loadedIconMap);

          setExpenses(loadedExpenses); 
          setCategoryStats(calculateStats(loadedExpenses, true)); 
          setCurrentMonth(result[3].values ? result[3].values[0][0] : 0);
          setPreviousMonth(result[4].values ? result[4].values[0][0] : 0);

          setMonthlyExpenses(loadedMonthlyExpenses);
          setMonthlyCategoryStats(calculateStats(loadedMonthlyExpenses, false));
          setMonthlyCurrentMonth(result[6].values ? result[6].values[0][0] : 0);
          setMonthlyPreviousMonth(result[7].values ? result[7].values[0][0] : 0);

          setProcessing(false);
        });
    });
  };

  const handleExpenseSubmit = () => {
    setProcessing(true); setShowExpenseForm(false);
    const isUpdate = !!expense.id;
    const sheetName = activeView === 'monthly' ? 'Monthly' : 'Expenses';
    
    // We explicitly USER_ENTERED so Google Sheets evaluates the =DATE(...) formula
    const apiCall = isUpdate 
        ? window.gapi.client.sheets.spreadsheets.values.update({ spreadsheetId: SPREADSHEET_ID, range: expense.id, valueInputOption: "USER_ENTERED", values: [formatExpense(expense)] })
        : window.gapi.client.sheets.spreadsheets.values.append({ spreadsheetId: SPREADSHEET_ID, range: `${sheetName}!A1`, valueInputOption: "USER_ENTERED", insertDataOption: "INSERT_ROWS", values: [formatExpense(expense)] });

    apiCall.then(() => {
        if(snackbarInstance.current) snackbarInstance.current.show({ message: `Expense ${isUpdate ? "updated" : "added"}!` });
        loadData();
    }).catch(err => {
        console.error("Submit Error", err);
        setProcessing(false);
    });
  };

  const handleExpenseDelete = (expToDelete) => {
    setProcessing(true); setShowExpenseForm(false);
    const [sheetName, cell] = expToDelete.id.split('!');
    const expenseRow = parseInt(cell.substring(1), 10);
    const sheetId = sheetIdMap[sheetName];

    window.gapi.client.sheets.spreadsheets.batchUpdate({
        spreadsheetId: SPREADSHEET_ID,
        resource: { requests: [{ deleteDimension: { range: { sheetId: sheetId, dimension: "ROWS", startIndex: expenseRow - 1, endIndex: expenseRow } } }] }
    }).then(() => {
        if(snackbarInstance.current) snackbarInstance.current.show({ message: "Expense deleted!" });
        loadData();
    });
  };

  // --- RENDER ---
  const renderDashboard = () => {
    const stats = activeView === 'monthly' ? monthlyCategoryStats : categoryStats;
    const title = activeView === 'monthly' ? "Monthly Bills Breakdown" : "This Month Breakdown";

    return (
    <div className="mdc-card" style={{ padding: '10px', marginBottom: '10px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h2 className="mdc-card__subtitle" style={{ margin: 0 }}>{title}</h2>
        <button className="mdc-button" onClick={() => setShowChart(!showChart)}>
           {showChart ? "Show List" : "Show Chart"}
        </button>
      </div>

      {showChart ? (
        <div style={{ width: '100%', height: 230, marginBottom: '35px'}}>
          {stats.length > 0 ? (
            <ResponsiveContainer>
              <PieChart>
                <Pie
                  data={stats}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                  onClick={handleSliceClick}
                  cursor="pointer"
                >
                  {stats.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} opacity={filterCategory === entry.name ? 1 : 0.7} />
                  ))}
                </Pie>
                <Tooltip formatter={(value) => `$${value.toFixed(2)}`} />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div className="center" style={{ paddingTop: '80px', color: '#999', fontStyle: 'italic' }}>
               {activeView === 'monthly' ? 'No monthly expenses found' : 'No expenses for this month'}
            </div>
          )}
          
          <div className="center" style={{fontSize: '0.8rem', color: '#666', marginTop: '25px'}}>
            {filterCategory ? `Filtering: ${filterCategory}` : (stats.length > 0 ? "Click a slice to filter" : "")}
          </div>
        </div>
      ) : (
        <ul className="mdc-list mdc-list--dense">
            {stats.length > 0 ? (
                stats.map((stat, index) => (
                    <li 
                    key={index} 
                    className="mdc-list-item" 
                    onClick={() => handleSliceClick(stat)}
                    style={{ cursor: 'pointer', backgroundColor: filterCategory === stat.name ? '#f0f0f0' : 'white' }}
                    >
                    <span className="mdc-list-item__text" style={{ marginRight: '10px'}}>{stat.name} : </span>
                    <span className="mdc-list-item__meta" style={{ color: COLORS[index % COLORS.length], fontWeight: 'bold' }}>
                        ${stat.value.toFixed(2)}
                    </span>
                    </li>
                ))
            ) : (
                <li className="mdc-list-item center">No data</li>
            )}
        </ul>
      )}
    </div>
  );
};
  const renderBody = () => {
    if (processing) return <LoadingBar />;
    if (showExpenseForm) return <ExpenseForm categories={categories} accounts={accounts} expense={expense} onSubmit={handleExpenseSubmit} onCancel={() => setShowExpenseForm(false)} onDelete={handleExpenseDelete} onChange={(attr, val) => setExpense(prev => ({ ...prev, [attr]: val }))} />;

    const expensesToRender = activeView === 'monthly' ? monthlyExpenses : expenses;
    const visibleExpenses = filterCategory 
      ? expensesToRender.filter(e => e.category === filterCategory)
      : expensesToRender;

    return (
      <div>
        <div style={{ textAlign: 'center', margin: '10px' }}>
          <button onClick={() => setActiveView('other')} className={`mdc-button ${activeView === 'other' ? 'mdc-button--raised' : ''}`}>Other</button>
          <button onClick={() => setActiveView('monthly')} className={`mdc-button ${activeView === 'monthly' ? 'mdc-button--raised' : ''}`}>Monthly</button>
        </div>

        <div className="mdc-card">
          <section className="mdc-card__primary" style={{ display: 'flex', justifyContent: 'space-around', textAlign: 'center' }}>
            <div>
              <h2 className="mdc-card__subtitle">Total Previous Month</h2>
              <h1 className="mdc-card__title mdc-card__title--large">
                {activeView === 'monthly' ? (monthlyPreviousMonth || '...') : (previousMonth || "...")}
              </h1>
            </div>
            <div>
              <h2 className="mdc-card__subtitle">Total This Month</h2>
              <h1 className="mdc-card__title mdc-card__title--large">
                {activeView === 'monthly' ? (monthlyCurrentMonth || '...') : (currentMonth || "...")}
              </h1>
            </div>
          </section>
        </div>
        
        {renderDashboard()}

        {filterCategory && (
            <div className="center" style={{ margin: '10px 0' }}>
                <button className="mdc-button mdc-button--outlined" onClick={() => setFilterCategory(null)}>
                    Clear Filter ({filterCategory})
                </button>
            </div>
        )}
        
        <ExpenseList 
            expenses={visibleExpenses.slice(0, 30)}
            onSelect={(e) => { setExpense(e); setShowExpenseForm(true); }} 
            iconMap={iconMap}
        />
        
        <button onClick={onExpenseNew} className="mdc-fab app-fab--absolute material-icons" aria-label="Add expense"><span className="mdc-fab__icon">add</span></button>
      </div>
    );
  };

  return (
    <div>
      <header className="mdc-toolbar mdc-toolbar--fixed">
        <div className="mdc-toolbar__row">
          <section className="mdc-toolbar__section mdc-toolbar__section--align-start"><span className="mdc-toolbar__title">Expenses</span></section>
          <section className="mdc-toolbar__section mdc-toolbar__section--align-end">
            {!signedIn ? <a className="material-icons mdc-toolbar__icon" onClick={() => login()}>perm_identity</a> : <a className="material-icons mdc-toolbar__icon" onClick={logout}>exit_to_app</a>}
          </section>
        </div>
      </header>
      <div className="toolbar-adjusted-content">
        {!signedIn ? <div className="center"><button className="mdc-button sign-in" onClick={() => login()}>Sign In with Google</button></div> : renderBody()}
      </div>
      <div ref={snackbarRef} className="mdc-snackbar" aria-live="assertive" aria-atomic="true" aria-hidden="true"><div className="mdc-snackbar__text" /><div className="mdc-snackbar__action-wrapper"><button type="button" className="mdc-button mdc-snackbar__action-button" aria-hidden="true" /></div></div>
    </div>
  );
};

export default App;